mapper.insert:
insert into `order_stage` (
    order_id, stage_no, stage_name, stage_desc, stage_amount, plan_start_at,
    plan_end_at, submit_content, deliverable_json, status, actual_start_at,
    actual_submit_at, actual_accept_at, reject_reason, version, created_at, updated_at
) values (
    #{orderId}, #{stageNo}, #{stageName}, #{stageDesc}, #{stageAmount}, #{planStartAt},
    #{planEndAt}, #{submitContent}, #{deliverableJson}, #{status}, #{actualStartAt},
    #{actualSubmitAt}, #{actualAcceptAt}, #{rejectReason}, #{version}, #{createdAt}, #{updatedAt}
)

mapper.select:
select 
from `order_stage`
where order_id = #{orderId}
  and stage_no = #{stageNo}
limit 1
